const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const FIRST_INSURANCE_SURCHARGE = 0.1;
const PROCESSING_FEE = 5;

// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));

// Components are priced in blocks: a block of exactly BLOCK_SIZE alike components
// costs BLOCK_PREMIUM; leftover components are priced individually.
const componentBasePremium = (count: number, perComponent: number): number => {
  const blocks = Math.floor(count / BLOCK_SIZE);
  const remainder = count % BLOCK_SIZE;
  return blocks * BLOCK_PREMIUM + remainder * perComponent;
};

const itemsBasePremium = (items: Item[]): number => {
  let total = 0;
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += BASE_PREMIUM[item.type];
    }
  }
  for (const type of Object.keys(componentCounts)) {
    total += componentBasePremium(componentCounts[type], BASE_PREMIUM[type]);
  }
  return total;
};

const quotePremium = (items: Item[]): number => {
  const itemsPremium = itemsBasePremium(items) * (1 + FIRST_INSURANCE_SURCHARGE);
  return roundPremiumUp(itemsPremium + PROCESSING_FEE);
};

