interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

type Step = QuoteStep;

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const FIRST_INSURANCE_SURCHARGE = 0.1;
const CURSE_SURCHARGE = 0.5;
const PROCESSING_FEE = 5;

// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));

// A block applies only to a group of exactly BLOCK_SIZE alike components,
// priced at BLOCK_PREMIUM; any other count is priced individually.
const componentBasePremium = (count: number, perComponent: number): number => {
  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
  return count * perComponent;
};

const sum = (amounts: number[]): number => amounts.reduce((acc, amount) => acc + amount, 0);

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
const isMainItem = (item: Item): boolean => !isComponent(item);

const countByType = (items: Item[]): Record<string, number> => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
};

// A surcharge rate is an additive percentage applied on top of a base premium.
const applySurcharge = (base: number, rate: number): number => base * (1 + rate);

// Item-specific surcharges are additive percentages of the item's base premium.
// First insurance applies to every item; the curse surcharge to cursed items.
const itemSurchargeRate = (item: Item): number => {
  const curse = item.cursed ? CURSE_SURCHARGE : 0;
  return FIRST_INSURANCE_SURCHARGE + curse;
};

const mainItemPremium = (item: Item): number =>
  applySurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));

const componentGroupPremium = (count: number, perComponent: number): number =>
  applySurcharge(componentBasePremium(count, perComponent), FIRST_INSURANCE_SURCHARGE);

const itemsPremium = (items: Item[]): number => {
  const componentCounts = countByType(items.filter(isComponent));

  const mainItemsPremium = sum(items.filter(isMainItem).map(mainItemPremium));
  const componentsPremium = sum(
    Object.entries(componentCounts).map(([type, count]) =>
      componentGroupPremium(count, BASE_PREMIUM[type]),
    ),
  );

  return mainItemsPremium + componentsPremium;
};

const quotePremium = (items: Item[]): number =>
  roundPremiumUp(itemsPremium(items) + PROCESSING_FEE);

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

