import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Edge cases: simplest ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(out.results[0]).toEqual({ premium: 5 });
  });

  // --- Base premiums for main items (single item, newcomer baseline) ---
  // Note: a lone item for a 0-year customer gets first-insurance +10% and fee.
  // Use these to pin base premiums via the integration math where needed.
  it("single sword, 0 years → base 100 G + 10% first + 5 fee = 115 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 115 });
  });
  it("single amulet, 0 years → base 60 G + 10% first + 5 fee = 71 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 71 });
  });
  it("single staff, 0 years → base 80 G + 10% first + 5 fee = 93 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "oak", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 93 });
  });
  it("single potion, 0 years → base 40 G + 10% first + 5 fee = 49 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 49 });
  });

  // --- Components: per-component premium and building block ---
  it("2 runes (25 each, no block) → base 50, +10% first +5 fee = 60 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(out.results[0]).toEqual({ premium: 60 });
  });
  it("3 runes form a block → base 60, +10% first +5 fee = 71 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 71 });
  });
  it("4 runes (no block — block requires exactly 3) → base 100, +10% +5 = 115 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 115 });
  });
  it("7 runes (no block) → base 175, +10% +5 = 197.5 → rounded up 198 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 198 });
  });

  // --- 'Alike' components ---
  it("2 runes + 1 moonstone (different types, no block) → base 75, +10% +5 = 88 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 88 });
  });
  it("3 runes + 3 moonstones (two separate blocks) → base 120, +10% +5 = 137 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 137 });
  });

  // --- Premium modifiers in isolation ---
  it("cursed sword (steel, ench 3), 0 years → 100 +50 curse +10 first +5 fee = 165 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 165 });
  });
  it("sword ench 5 (high-ench threshold) → 100 +30 +10 first +5 fee = 145 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 145 });
  });
  it("sword ench 4 (below threshold) → no high-ench; 100 +10 first +5 = 115 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 115 });
  });
  it("sword ench 5 + cursed → both surcharges; 100 +50 +30 +10 +5 fee = 195 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 195 });
  });
  it("2 years (loyalty threshold), plain sword → 110 −20 loyalty +5 fee = 95 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(out.results[0]).toEqual({ premium: 95 });
  });
  it("second quote in scenario gets follow-up −15%: [115, 100]", () => {
    const sword = { type: "sword", material: "steel", enchantment: 3, cursed: false };
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [sword] },
        { op: "quote", items: [sword] },
      ],
    });
    expect(out.results).toEqual([{ premium: 115 }, { premium: 100 }]);
  });

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword (100) + plain amulet (60) → policy base 160; curse adds 50 (50% of sword) → 210 before further modifiers and fee");

  // --- Rounding ---
  it.todo("premium yielding 197.5 G → final premium 198 G (rounded up)");
  it.todo("payout yielding 350.5 G → final payout 350 G (rounded down)");

  // --- Integration examples ---
  it.todo("newcomer cursed sword (steel, ench 3): 100 base + 50 curse + 10 first = 160 + 5 fee = 165 G");
  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7) → 160 G (100 +50 +30 -20 +10 -15 = 155 +5 fee)");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("damage to a rune (value 250), damage 200 → payout 100 (full minus 100 deductible)");

  // --- Claim: enchantment threshold and dragon material ---
  it.todo("steel sword, ench 9, damage 1000 → payout 400 (50% then deductible: 500-100)");
  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (full, then deductible: 800-100)");
  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (50% wins, then deductible: 500-100)");
  it.todo("dragon-material sword, ench 8, damage 1000 → payout 400 (high-ench clause applies, then deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per damaged item)");

  // --- Claim: cap ---
  it.todo("policy covers sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword → cap 2000 (based on unmodified insurance value, premium modifiers do not raise cap)");
  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 (block discount affects premium only)");
  it.todo("sword (cap 2000), two successive 1500 claims: first → payout 1400, remainingCap 600; second → payout 600, remainingCap 0");

  // --- Multiple items of same type ---
  it.todo("policy covers two swords → insurance sum 2000, cap 4000; dragon attack damages both → each its own deductible");

  // --- Error cases ---
  it.todo("quote with unknown item type (broomstick) → throws / non-zero exit");
  it.todo("claim references item not in policy (amulet when only sword insured) → throws / non-zero exit");
  it.todo("claim with more damage entries of a type than insured (two swords, one insured) → throws / non-zero exit");
  it.todo("claim with negative damage amount (-200) → throws / non-zero exit");
});

