const insuranceSum = (items: Item[]): number =>
  sum(items.map((item) => INSURANCE_VALUE[item.type]));

const damagePayout = (damage: Damage): number => Math.max(0, damage.amount - DEDUCTIBLE);

const claimResult = (
  policyItems: Item[],
  incident: ClaimStep["incident"],
): { payout: number; remainingCap: number } => {
  const cap = CAP_MULTIPLIER * insuranceSum(policyItems);
  const payout = sum(incident.damages.map(damagePayout));
  return { payout, remainingCap: cap - payout };
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const { yearsWithMHPCO } = scenario.customer;
  const policies: Record<number, Item[]> = {};
  let quoteCount = 0;

